text:
{
  "formal_minutes": {
    "project_code": "PUBLIC_MEETING_SMOKE",
    "meeting_title": "UI Theme Package Release Readiness",
    "participants": [
      "Minjun",
      "Seoyeon",
      "Doyun",
      "Hara"
    ],
    "confirmed_decisions": [
      {
        "decision": "공개 릴리스 목표는 금요일 15:00 KST로 잡는다.",
        "condition": "스모크 테스트가 통과해야 한다."
      },
      {
        "decision": "packageName 불일치가 발생하면 먼저 패키지 설정을 확인한다.",
        "condition": "스크립트 자체를 검토하는 것은 계약(contract) 자체가 잘못된 경우에만 한다."
      }
    ],
    "rejected_proposals": [
      {
        "proposal": "smoke-theme-pack.mjs에서 packageName 불일치를 무시하도록 변경한다.",
        "status": "거절됨"
      },
      {
        "proposal": "수요일 공개 릴리스를 확정한다.",
        "status": "채택되지 않음"
      }
    ],
    "internal_stretch_goals": [
      {
        "item": "수요일 릴리스",
        "status": "내부 스트레치 목표로만 언급됨",
        "decision_status": "확정 아님"
      },
      {
        "item": "README 설치 단계 검토",
        "status": "가능하면 목요일까지 검토",
        "decision_status": "오너 미지정, 확정 아님"
      }
    ],
    "risks": [
      {
        "risk": "잘못된 tarball 경로로 인해 릴리스가 지연될 수 있음."
      },
      {
        "risk": "README 설치 단계가 오래되면 릴리스 노트가 사용자에게 잘못된 정보를 줄 수 있음."
      }
    ],
    "open_questions": [
      {
        "question": "최종 릴리스 승인 권한은 누구에게 있는가?"
      },
      {
        "question": "릴리스 노트에 내부 수요일 스트레치 목표를 언급해야 하는가?"
      }
    ],
    "non_decisions": [
      {
        "item": "수요일 공개 릴리스",
        "reason": "내부 스트레치 목표로만 남았고 최종 결정이 아님"
      },
      {
        "item": "README 설치 단계 검토",
        "reason": "검토 필요성이 언급되었지만 오너와 확정 일정이 없음"
      }
    ]
  },
  "action_items": [
    {
      "owner": "Minjun",
      "task": "스모크 테스트를 다시 실행하고 결과를 공유한다.",
      "due": "금요일 10:00 KST",
      "status": "확정",
      "source_certainty": "confirmed"
    },
    {
      "owner": "Doyun",
      "task": "실패 triage 노트를 action_items.md에 작성한다.",
      "due": "금요일 12:00 KST",
      "status": "확정",
      "source_certainty": "confirmed"
    },
    {
      "owner": "Hara",
      "task": "Minjun이 스모크 결과를 올린 뒤 생성된 tarball 경로를 확인한다.",
      "due": "미정",
      "status": "확정",
      "source_certainty": "confirmed"
    },
    {
      "owner": "미지정",
      "task": "README 설치 단계를 검토한다.",
      "due": "목요일까지 검토가 바람직하다고 언급됨",
      "status": "미할당",
      "source_certainty": "confirmed_without_owner"
    }
  ],
  "followup_note": {
    "what_to_check_next": [
      "금요일 10:00 KST까지 Minjun의 스모크 테스트 결과를 확인한다.",
      "스모크 통과 여부를 확인한 뒤에만 공개 릴리스 진행 여부를 판단한다.",
      "tarball 경로가 올바른지 확인한다.",
      "README 설치 단계가 최신인지 점검한다.",
      "최종 릴리스 승인 권한자를 확인한다.",
      "내부 수요일 스트레치 목표를 릴리스 노트에 넣을지 결정한다."
    ],
    "what_not_to_invent": [
      "고객명",
      "외부 파트너명",
      "예산",
      "보안 사고",
      "프로덕션 장애",
      "법무 승인 요구사항",
      "오너가 지정되지 않은 작업의 담당자",
      "명시되지 않은 마감일"
    ]
  },
  "non_invention_rules": [
    "고객 또는 외부 파트너는 명시되지 않았으므로 이름을 만들지 않는다.",
    "예산, 보안 사고, 프로덕션 장애, 법무 승인 요구사항은 언급되지 않았으므로 추가하지 않는다.",
    "오너가 정해지지 않은 항목은 미지정으로 유지하고 임의로 배정하지 않는다.",
    "명시된 시각과 날짜만 사용하고, 새로운 데드라인을 추정하지 않는다.",
    "결정, 거절, 위험, 질문은 원문에서 확인된 내용만 반영한다.",
    "내부 스트레치 목표는 확정 결정으로 승격하지 않는다."
  ]
}
